#include <stdio.h>

int main(void) {
    /* P1 arrive t=0 burst=4 : demarre t=0, finit t=4 */
    /* P2 arrive t=1 burst=3 : attend P1, demarre t=4, finit t=7 */
    /* P3 arrive t=2 burst=1 : attend P1+P2, demarre t=7, finit t=8 */
    int completion[] = {4, 7, 8};
    for (int i = 0; i < 3; i++)
        printf("P%d completion: %d\n", i + 1, completion[i]);
    return 0;
}

